echo"<script>
document.addEventListener('DOMContentLoaded', function () {
    // Temukan dropdown tahun yang kedua (input nilai tahun)
    const tahunInputs = document.querySelectorAll('select[name^='value_tahun']');
    const tombolCari = document.querySelector('[data-itemid='cari']');

    // Sembunyikan tombol 'oke' saat awal
    if (tombolCari) {
        tombolCari.style.display = 'none';
    }

    // Fungsi cek apakah nilai tahun valid
    function checkTahun() {
        if (!tahunInputs.length || !tombolCari) return;

        const selectedValue = tahunInputs[0].value;
        if (selectedValue !== '') {
            tombolCari.style.display = 'inline-block';
        } else {
            tombolCari.style.display = 'none';
        }
    }

    // Tambahkan event listener ke semua dropdown tahun
    tahunInputs.forEach(input => {
        input.addEventListener('change', checkTahun);
    });

    // Jalankan sekali saat halaman dimuat
    checkTahun();
});
</script>
